import{_ as e,o,c as a,a2 as i}from"./chunks/framework.DGp-bpT-.js";const m=JSON.parse('{"title":"Communicating with the Bot and Interaction Rules","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/interaction.md","filePath":"en/guide/interaction.md","lastUpdated":null}'),n={name:"en/guide/interaction.md"};function s(r,t,l,u,h,c){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="communicating-with-the-bot-and-interaction-rules" tabindex="-1">Communicating with the Bot and Interaction Rules <a class="header-anchor" href="#communicating-with-the-bot-and-interaction-rules" aria-label="Permalink to &quot;Communicating with the Bot and Interaction Rules&quot;">​</a></h1><p>The SREBot platform allows you not only to receive automatic alert analysis (RCA) but also to dialogue with the bot in chat to clarify details.</p><h2 id="how-to-ask-a-follow-up-question" tabindex="-1">How to Ask a Follow-up Question <a class="header-anchor" href="#how-to-ask-a-follow-up-question" aria-label="Permalink to &quot;How to Ask a Follow-up Question&quot;">​</a></h2><p>To ask the bot a question about a specific incident:</p><ol><li>Find the bot&#39;s message with the analysis (RCA) in the Telegram channel or chat.</li><li>Reply to this message (<strong>Reply</strong>) with your question.</li><li>The bot will see your reply, show an &quot;Analyzing...&quot; status, and send the clarified information.</li></ol><h2 id="rules-for-interacting-with-the-bot" tabindex="-1">Rules for Interacting with the Bot <a class="header-anchor" href="#rules-for-interacting-with-the-bot" aria-label="Permalink to &quot;Rules for Interacting with the Bot&quot;">​</a></h2><p>To ensure the bot works efficiently and does not waste your tokens, please follow these rules:</p><h3 id="_1-topic-of-questions" tabindex="-1">1. Topic of Questions <a class="header-anchor" href="#_1-topic-of-questions" aria-label="Permalink to &quot;1. Topic of Questions&quot;">​</a></h3><p>The bot is designed as a professional SRE assistant. It responds <strong>only to questions related to the current incident</strong>, the provided analysis, or general diagnostics and observability tasks.</p><p><strong>Examples of good questions:</strong></p><ul><li><em>“Show logs for the last 10 minutes from this node”</em></li><li><em>“What was the CPU usage at the time of the alert?”</em></li><li><em>“What other alerts triggered in this cluster within the hour?”</em></li></ul><p><strong>Off-topic Protection:</strong> If you ask the bot about something unrelated to the incident (e.g., <em>“tell a joke”</em> or <em>“how are you”</em>), the bot will politely refuse to answer to save your organization&#39;s token balance.</p><h3 id="_2-communication-language" tabindex="-1">2. Communication Language <a class="header-anchor" href="#_2-communication-language" aria-label="Permalink to &quot;2. Communication Language&quot;">​</a></h3><p>The bot can communicate in different languages. The response language is configured in the control panel or via the <code>LLM_RESPONSE_LANGUAGE</code> environment variable. If you want the bot to respond in Russian, make sure this parameter is set to <code>Russian</code>.</p><h3 id="_3-constraints-limits" tabindex="-1">3. Constraints (Limits) <a class="header-anchor" href="#_3-constraints-limits" aria-label="Permalink to &quot;3. Constraints (Limits)&quot;">​</a></h3><p>To protect against infinite loops and spam, the following limits apply:</p><ul><li><strong>Cooldown</strong>: there must be a pause between questions from the same user (default is 5 seconds).</li><li><strong>Maximum turns</strong>: a limited number of questions can be asked per incident (default is 5). If the limit is exceeded, the bot will notify you.</li></ul><p>These parameters are configured on the bot side (<code>FOLLOWUP_COOLDOWN</code>, <code>FOLLOWUP_MAX_TURNS</code>).</p>',18)])])}const p=e(n,[["render",s]]);export{m as __pageData,p as default};
